const resp = $input.first().json;
const result = resp.result || resp;

const webhookUrl = result.url || '';
const pending = result.pending_update_count || 0;
const lastErrorDate = result.last_error_date ? new Date(result.last_error_date * 1000).toISOString() : null;
const lastErrorMsg = result.last_error_message || '';
const expectedUrl = 'bandomasis.app.n8n.cloud';

const issues = [];

if (!webhookUrl) {
  issues.push('CRITICAL: Webhook URL is EMPTY — bot receives NO messages');
} else if (!webhookUrl.includes(expectedUrl)) {
  issues.push('WARNING: Webhook URL does not point to expected n8n Cloud: ' + webhookUrl);
}

if (pending > 10) {
  issues.push('WARNING: ' + pending + ' pending updates — messages may be stuck');
}

if (lastErrorDate) {
  const errorAge = Date.now() - new Date(lastErrorDate).getTime();
  if (errorAge < 3600000) {
    issues.push('ERROR: Recent webhook error (' + lastErrorDate + '): ' + lastErrorMsg);
  }
}

const healthy = issues.length === 0;

return [{ json: {
  healthy,
  webhookUrl,
  pending,
  lastErrorDate,
  lastErrorMsg,
  issues,
  checkedAt: new Date().toISOString()
} }];

const data = $input.first().json;
const issues = data.issues || [];

let msg = '⚠️ TELEGRAM WEBHOOK UNHEALTHY\n\n';
msg += 'Time: ' + data.checkedAt + '\n';
msg += 'URL: ' + (data.webhookUrl || 'MISSING') + '\n';
msg += 'Pending: ' + data.pending + '\n';
if (data.lastErrorDate) {
  msg += 'Last Error: ' + data.lastErrorDate + '\n';
  msg += 'Error Msg: ' + data.lastErrorMsg + '\n';
}
msg += '\nIssues:\n';
issues.forEach(i => { msg += '• ' + i + '\n'; });
msg += '\nAction: Check n8n Cloud workflow activation and Telegram bot status.';

return [{ json: { chatId: '8747048300', text: msg } }];
